using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;

public class ButtonEvents : MonoBehaviour
{
    // UI elements
    public GameObject mainMenu;
    public GameObject pauseMenu;
    public GameObject gameOverMenu;

    public Button startButton;
    public Button pauseButton;
    public Button resumeButton;
    public Button restartButton;
    public Button quitButton;

    public Slider volumeSlider;
    public Toggle soundToggle;
    public Dropdown difficultyDropdown;

    private bool isPaused = false;

    void Start()
    {
        // Add listeners to buttons
        if (startButton != null)
            startButton.onClick.AddListener(StartGame);

        if (pauseButton != null)
            pauseButton.onClick.AddListener(PauseGame);

        if (resumeButton != null)
            resumeButton.onClick.AddListener(ResumeGame);

        if (restartButton != null)
            restartButton.onClick.AddListener(RestartGame);

        if (quitButton != null)
            quitButton.onClick.AddListener(QuitGame);

        // Add listeners to slider
        if (volumeSlider != null)
            volumeSlider.onValueChanged.AddListener(OnVolumeChanged);

        // Add listeners to toggle
        if (soundToggle != null)
            soundToggle.onValueChanged.AddListener(OnSoundToggled);

        // Add listeners to dropdown
        if (difficultyDropdown != null)
            difficultyDropdown.onValueChanged.AddListener(OnDifficultyChanged);

        // Show main menu, hide others
        ShowMainMenu();
    }

    public void StartGame()
    {
        Debug.Log("Game started!");
        mainMenu.SetActive(false);
        pauseMenu.SetActive(false);
        gameOverMenu.SetActive(false);
        Time.timeScale = 1f;
    }

    public void PauseGame()
    {
        isPaused = !isPaused;

        if (isPaused)
        {
            Time.timeScale = 0f;
            pauseMenu.SetActive(true);
            Debug.Log("Game paused");
        }
        else
        {
            Time.timeScale = 1f;
            pauseMenu.SetActive(false);
            Debug.Log("Game resumed");
        }
    }

    public void ResumeGame()
    {
        isPaused = false;
        Time.timeScale = 1f;
        pauseMenu.SetActive(false);
        Debug.Log("Game resumed");
    }

    public void RestartGame()
    {
        Debug.Log("Game restarted!");
        Time.timeScale = 1f;
        SceneManager.LoadScene(SceneManager.GetActiveScene().name);
    }

    public void QuitGame()
    {
        Debug.Log("Quitting game...");
        #if UNITY_EDITOR
        UnityEditor.EditorApplication.isPlaying = false;
        #else
        Application.Quit();
        #endif
    }

    public void ShowMainMenu()
    {
        mainMenu.SetActive(true);
        pauseMenu.SetActive(false);
        gameOverMenu.SetActive(false);
    }

    public void ShowGameOver()
    {
        gameOverMenu.SetActive(true);
        Debug.Log("Game Over!");
    }

    // UI event handlers
    void OnVolumeChanged(float value)
    {
        Debug.Log("Volume changed to: " + value);
        // Update audio mixer
    }

    void OnSoundToggled(bool value)
    {
        Debug.Log("Sound toggled to: " + value);
        // Enable/disable sound
    }

    void OnDifficultyChanged(int value)
    {
        string[] difficulties = { "Easy", "Medium", "Hard" };
        Debug.Log("Difficulty changed to: " + difficulties[value]);
        // Apply difficulty
    }

    // Example: Add listener at runtime
    public void AddButtonListener(Button button, System.Action action)
    {
        if (button != null)
        {
            button.onClick.AddListener(() => action());
        }
    }

    // Example: Remove all listeners
    public void RemoveAllListeners(Button button)
    {
        if (button != null)
        {
            button.onClick.RemoveAllListeners();
        }
    }
}

