using UnityEngine;
using UnityEngine.UI;

public class ButtonError : MonoBehaviour
{
    public Button myButton;

    void Start()
    {
        // Forgot to add listener!
        // myButton.onClick.AddListener(OnButtonClick);
    }

    void OnButtonClick()
    {
        Debug.Log("Button clicked!");  // Never called
    }
}

phase2.explanation:
You didn't add a listener to the button, so nothing happens when it's clicked.

**The fix:**
```csharp
void Start()
{
    if (myButton != null)
    {
        myButton.onClick.AddListener(OnButtonClick);
    }
}
```

**Sharp-chan says:**
"Buttons need listeners. Without them, they do nothing."
